#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x = 0) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* sortList(ListNode* head) {
        if (!head || !head->next) return head;
        ListNode* mid = getMid(head);
        ListNode* right = mid->next;
        mid->next = nullptr;
        ListNode* left = sortList(head);
        right = sortList(right);
        return merge(left, right);
    }
private:
    ListNode* getMid(ListNode* node) {
        ListNode* slow = node;
        ListNode* fast = node->next;
        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
        }
        return slow;
    }
    ListNode* merge(ListNode* l1, ListNode* l2) {
        ListNode dummy(0);
        ListNode* tail = &dummy;
        while (l1 && l2) {
            if (l1->val <= l2->val) {
                tail->next = l1;
                l1 = l1->next;
            } else {
                tail->next = l2;
                l2 = l2->next;
            }
            tail = tail->next;
        }
        tail->next = l1 ? l1 : l2;
        return dummy.next;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    ListNode dummy(0);
    ListNode* cur = &dummy;
    for (int i = 0; i < n; ++i) {
        int v; cin >> v;
        cur->next = new ListNode(v);
        cur = cur->next;
    }
    Solution sol;
    ListNode* sorted = sol.sortList(dummy.next);
    for (ListNode* p = sorted; p; p = p->next) {
        cout << p->val;
        if (p->next) cout << '\n';
    }
    return 0;
}
